@Test
fun `simple test - scan emission works`() = runTest(testDispatcher) {
    scannerManager.register()

    // Collect one event
    val events = mutableListOf<ScanResult>()
    val job = launch {
        scannerManager.scanEvents.collect {
            events.add(it)
        }
    }

    // Give collector time to start
    testScheduler.runCurrent()

    // Emit scan
    val intent = createScanIntent("TEST123", "EAN13")
    simulateScanBroadcast(intent)

    // Process emissions
    testScheduler.advanceUntilIdle()

    // Verify
    assertEquals(1, events.size)
    assertEquals("TEST123", events[0].barcode)

    job.cancel()
}

